import {EventEmitter} from 'events';
import syslog = require('syslog-client');

import {FormatHelper} from './utils';

const syslogInfo = {
    port: 514,
    target: "127.0.0.1"
};


class SyslogBackend extends EventEmitter {  // gets original arguments
    private _client:syslog.Client;
    private _enabled:boolean;
    private _isWriting:boolean;
    private _writeQueue:Object[];
    private _test:string[];
    
    constructor() {
        super();
        this._isWriting = false;
        this._writeQueue = [];
        this._client = undefined;
        this._enabled = false;
        this._test = []; // map of what "names" can go to syslog

        if(process.platform === 'linux' && process.arch === 'arm') {
            this._enabled = true;
        }
        else {
            this._enabled = false; // don't bother on anything other than our linux/arm environment
        }

        // if we are turning on syslogging and there isn't a client, then start the client
        if (this._enabled && !this._client) {
            let options = {
                port: syslogInfo.port,
                transport: syslog.Transport.Udp
            };
            this._client = syslog.createClient(syslogInfo.target, options);
            console.warn("Initializing a syslog client");

            this._client.on("error", function (error) {
                console.error(error);
                if (this._client) {
                    this._client.close();
                    this._client = undefined;
                }
            });
        }

        // if we are turning off syslogging and there currently is a client, then close the client
        if (!this._enabled && this._client) {
            this._client.close();
            this._client = undefined;
        }

    }

    // allow logging with this name to go to syslog
    allow(name:string) {
        if (name) {
            this._test.push(name);
        }
    }


    processNextInQueue() {
        if(this._writeQueue.length === 0) {
            this._isWriting = false;
            return;
        }

        const {name, level, args} = <any>(this._writeQueue.shift());
        let type = undefined;
        switch(level) {
            case 'log':
            case 'debug': {
                type = "Debug";
                break;
            }
            case 'warn': {
                type = "Warning";
                break;
            }
            case 'error': {
                type = "Error";
                break;
            }
            case 'info':
            default: {
                type = "Informational";
                break;
            }
        }


        let logOptions = {
            facility: syslog.Facility.Local0,
            severity: syslog.Severity[type]
        };

        let msg = FormatHelper(args);
        this._isWriting = true;
        this._client.log(`${name}: [${level}] ${msg}`, logOptions, (error) => {
            if (error) {
                console.error(error);
            }
            // SDK-529 this .close() was apparently working around a bug in syslog-client,
            // which has now been fixed by this PR:
            // https://github.com/paulgrove/node-syslog-client/pull/7/files
            // which got merged into syslog-client starting in v1.0.10
            // the queueing logic can probably go away too, but i'm leaving it for now -jon
            //this._client.close();
            this.processNextInQueue();
        });
    }

    write(name, level, args) {  // EventEmitter
        // only write to syslog if it's enabled, has a client and the name exists in global mapping
        if (this._enabled && this._client && (this._test.indexOf(name) >= 0)) {
            this._writeQueue.push({name, level, args});
            if (!this._isWriting) {
                this.processNextInQueue();
            }
        }
    }
}


export default SyslogBackend;
