import * as fs from 'fs-extra';
import * as path from 'path';
import {EventEmitter} from 'events';

import {FormatHelper, Level} from './utils';

const loggingToFiles = {};  // index of all files being logged to


class FileBackend extends EventEmitter {  // gets original arguments
    private _filename:string;
    private _directory:string;
    private _file:fs.WriteStream;
    
    constructor(filename?:string, directory?:string) {
        super();
        this._filename = filename;
        this._directory = directory;
        this._file = undefined;

        if (!this._filename) {
            let timestamp:string = new Date().toISOString();
            if (process.platform === 'win32') {
                // replace all ':'s for '_'s as windows file paths cannot have that character in them
                timestamp = timestamp.replace(/:/g, '_');
            }
            this._filename = 'skill.' + timestamp + '.log';
        }

        if (!this._directory && !path.isAbsolute(this._filename)) {
            // see if we are running on robot
            if (process.platform === 'linux' && process.arch === 'arm' && fs.existsSync('/var/jibo')) {
                this._directory = '/var/log/jibo';
            } else {
                this._directory = path.join(process.env.HOME || process.env.USERPROFILE, '.jibo', 'logs');
            }
        }
    }


    init(callback?:Function) {

        this.createDirectory( () => {
            let fullFilename:string = path.normalize(this._filename);
            if (!path.isAbsolute(fullFilename)) {
                fullFilename = path.join(this._directory, fullFilename);
            }
            fullFilename = path.resolve(fullFilename);

            if (!loggingToFiles[fullFilename]) {
                loggingToFiles[fullFilename] = this;
                console.log('jibo.log: logging to', fullFilename);
                this._file = fs.createWriteStream(fullFilename, {'flags': 'a'});  // append
            } else {
                console.log('jibo.log: already logging to', fullFilename);
            }

            if (callback) {
                callback();
            }
        });
    }


    write(name:string, level:Level, args:any[]) {
        const timestamp:string = new Date().toISOString();
        const text:string = FormatHelper(args);
        const message:string = timestamp + ' '
            + (name ? name + ' ' : '')
            + (level ? level + ' ' : '')
            + text;

        this._file.write(message + '\n');
    }


    createDirectory(callback:Function) {
        if (this._directory && !path.isAbsolute(this._filename)) {
            fs.ensureDir(this._directory, (err) => {
                if (err) {
                    console.error('jibo.log: error creating directory', this._directory, err);
                }
                callback();
            });
        } else {
            setImmediate(callback);
        }
    }
}


export default FileBackend;




