global.JiboSingletons = global.JiboSingletons || {};

declare var global:any;


class JiboSingletons {
    // check an instantiated class and return it or it's previously instantiated singleton
    static enforceSingleton<T>(candidate: {new(): T}):T;
    static enforceSingleton(candidate:Function):Function;
    static enforceSingleton(candidate:any|Function):any|Function {
        let singleton:any = candidate;
        let singletonName:string = candidate.constructor.name;
        if (!global.JiboSingletons[singletonName]) {
            global.JiboSingletons[singletonName] = singleton;
        } else {
            singleton = global.JiboSingletons[singletonName];

            if (singletonName === 'Function') {   // fixes a bug where jibo-log reports as 'Function'
                singletonName = 'jibo-log';
            }
            // let's only warn if the versions don't match
            // console.warn('JiboSingletons: using existing Jibo singleton', singletonName);

            // optionally check if versions match (and warn if not)
            if (candidate.version) {
                let candidateVersion:string|Function = candidate.version;
                let singletonVersion = singleton.version;
                if (typeof candidate.version === 'function') {
                    candidateVersion = candidate.version();
                }
                if (typeof singleton.version === 'function') {
                    singletonVersion = singleton.version();
                }
                if (candidateVersion !== singletonVersion) {
                    console.log(singletonName, 'singleton: existing version', singletonVersion,
                                'does not equal candidate version', candidateVersion);
                }
            }
        }
        return singleton;
    }
}


export default JiboSingletons;
