import JiboLog from './JiboLog';
import {Level} from './utils';

function warn(msg:string) {
    let stack = new Error().stack;
    stack = stack.split('\n').splice(3).join('\n');
    if ((console as any).groupCollapsed) {
        (console as any).groupCollapsed("%cDeprecation Warning: %c%s", "color:#614108;background:#fffbe6", "font-weight:normal;color:#614108;background:#fffbe6", msg);
        console.warn(stack);
        console.groupEnd();
    }
    else {
        console.warn("Deprecation Warning:", msg);
        console.warn(stack);
    }
}

const JiboLogPrototype:any = JiboLog.prototype;

/**
 * Allow handling uncaught and unhandled exceptions.
 * @method JiboLog#enableUncaughtAndUnhandled
 * @deprecated since 1.1.0
 * @see JiboLog#handleAll
 */
JiboLogPrototype.enableUncaughtAndUnhandled = function():void {
    warn('enableUncaughtAndUnhandled is deprecated, please use handleAll, e.g., log.handleAll = true');
    this.handleAll = true;
};

/**
 * Allow handling uncaught and unhandled exceptions.
 * @method JiboLog#disableUncaughtAndUnhandled
 * @deprecated since 1.1.0
 * @see JiboLog#handleAll
 */
JiboLogPrototype.disableUncaughtAndUnhandled = function():void {
    warn('disableUncaughtAndUnhandled is deprecated, please use handleAll, e.g., log.handleAll = false');
    this.handleAll = false;
};

/**
 * Set the default logging directory.
 * @method JiboLog#setDefaultLogDir
 * @deprecated since 1.1.0
 * @see JiboLog#defaultDir
 */
JiboLogPrototype.setDefaultLogDir = function(dir:string, callback?:Function):void {
    warn('setDefaultLogDir is deprecated, please use setDefaultDir, e.g., log.setDefaultDir(dir, callback)');
    this.defaultDir = dir;
    if (callback) {
        setImmediate(callback);
    }
};

/**
 * Allow for debug messages.
 * @method JiboLog#enableDebug
 * @deprecated since 1.1.0
 * @see JiboLog#minLevel
 */
JiboLogPrototype.enableDebug = function(name?:string|RegExp, level:Level=Level.debug):void {
    warn('enableDebug is deprecated, please use allow, e.g., log.minLevel = \'debug\'');
    this.minLevel = level;
};