import JiboLog from './JiboLog';
import './deprecation';

/**
 * Centralized logging facility.
 * @module jibo-log
 * @see JiboLog
 * @example
 * import * as JiboLog from 'jibo-log';
 * const log = new JiboLog(module.filename);
 * log.info('hello!');
 */

// we want to insure there is only ever one instance of the JiboLog module
// because of the file scope variables and especially the Minilog instance
import JiboSingletons from './JiboSingletons';
export default JiboSingletons.enforceSingleton(JiboLog);
